// Store original message for later
msg.originalLLMRequest = {
    userQuestion: msg.data?.recordDetails?.userQuestion,
    selectedProvider: msg.data?.recordDetails?.selectedProvider || 'openai',
    conversationContext: msg.data?.recordDetails?.conversationContext || [],
    session: msg.data?.session,
    params: msg.data?.recordDetails?.params || {}
};

// Build Trino context query
const params = msg.originalLLMRequest.params;
const startTs = params.start_ts || new Date(Date.now() - 7*24*60*60*1000).toISOString();
const endTs = params.end_ts || new Date().toISOString();

// Keycloak token request
const tokenUrl = env.get('FACIS_KEYCLOAK_URL') || 'https://identity.facis.cloud/realms/facis/protocol/openid-connect/token';
const clientId = env.get('FACIS_OIDC_CLIENT_ID') || 'trino';
const clientSecret = env.get('FACIS_OIDC_CLIENT_SECRET') || '';
const username = env.get('FACIS_TRINO_USER') || 'admin';
const password = env.get('FACIS_TRINO_PASSWORD') || '';

msg.url = tokenUrl;
msg.method = 'POST';
msg.headers = { 'Content-Type': 'application/x-www-form-urlencoded' };
msg.payload = `grant_type=password&client_id=${clientId}&client_secret=${clientSecret}&username=${username}&password=${password}&scope=openid`;

msg.trinoQuery = {
    startTs: startTs,
    endTs: endTs
};

return msg;

const token = msg.payload?.access_token;
if (!token) {
    node.warn('Failed to get Keycloak token, proceeding without Trino context');
    msg.trinoContext = { error: 'No Trino context available (auth failed)' };
    return [null, msg]; // Skip Trino, go to LLM directly
}

const trinoHost = env.get('FACIS_TRINO_HOST') || '212.132.83.150';
const trinoPort = env.get('FACIS_TRINO_PORT') || '8443';
const startTs = msg.trinoQuery?.startTs;
const endTs = msg.trinoQuery?.endTs;

// Query recent Gold Layer data for context
const sql = `SELECT \n    hour,\n    avg_consumption_kw,\n    avg_generation_kw,\n    net_grid_kw,\n    estimated_hourly_cost_eur\nFROM gold.net_grid_hourly\nWHERE hour >= from_iso8601_timestamp('${startTs}')\n  AND hour < from_iso8601_timestamp('${endTs}')\nORDER BY hour DESC\nLIMIT 48`;

msg.url = `https://${trinoHost}:${trinoPort}/v1/statement`;
msg.method = 'POST';
msg.headers = {
    'Authorization': 'Bearer ' + token,
    'Content-Type': 'text/plain',
    'X-Trino-User': env.get('FACIS_TRINO_USER') || 'admin',
    'X-Trino-Catalog': 'hive',
    'X-Trino-Schema': 'default'
};
msg.payload = sql;
msg.trinoToken = token;

return [msg, null];

// Extract data from Trino REST API response
const data = msg.payload;
let contextData = [];

try {
    if (data && data.data) {
        const columns = data.columns || [];
        const colNames = columns.map(c => c.name);
        contextData = data.data.map(row => {
            let obj = {};
            row.forEach((val, i) => {
                obj[colNames[i] || 'col_' + i] = val;
            });
            return obj;
        });
    }
} catch(e) {
    node.warn('Trino parse error: ' + e.message);
}

msg.trinoContext = {
    dataPoints: contextData.length,
    recentData: contextData.slice(0, 24),
    summary: contextData.length > 0 ? {
        latestHour: contextData[0]?.hour || 'unknown',
        avgNetGrid: contextData.length > 0 
            ? (contextData.reduce((s, r) => s + (parseFloat(r.net_grid_kw) || 0), 0) / contextData.length).toFixed(2) 
            : 'N/A',
        avgCost: contextData.length > 0 
            ? (contextData.reduce((s, r) => s + (parseFloat(r.estimated_hourly_cost_eur) || 0), 0) / contextData.length).toFixed(2) 
            : 'N/A'
    } : { note: 'No data available for the selected time range' }
};

return msg;

const req = msg.originalLLMRequest;
const context = msg.trinoContext || { note: 'No data context available' };

const systemPrompt = `You are the FACIS AI Insight Assistant for IoT and Smart City data analysis.\n\nYou have access to the following Gold Layer data context from the FACIS Lakehouse:\n${JSON.stringify(context, null, 2)}\n\nAvailable data sources:\n- Energy: hourly grid consumption/generation, daily costs, PV self-consumption\n- Smart City: streetlight zones, traffic patterns, city events, weather\n- Anomalies: statistical outlier candidates\n\nGuidelines:\n- Base your answers ONLY on the provided data context\n- If data is insufficient, say so explicitly\n- Provide specific numbers, timestamps, and metrics when available\n- Format responses with clear sections using Markdown\n- Keep responses concise but informative\n- Do not invent data points not present in the context`;

// Build messages array
const messages = [];

// Add conversation context for follow-ups
if (req.conversationContext && req.conversationContext.length > 0) {
    req.conversationContext.forEach(cm => {
        messages.push({ role: cm.role, content: cm.content });
    });
}

// Add current question
messages.push({ role: 'user', content: req.userQuestion });

msg.llmMessages = messages;
msg.llmSystemPrompt = systemPrompt;
msg.selectedProvider = req.selectedProvider || 'openai';

return msg;

const apiKey = env.get('FACIS_OPENAI_API_KEY') || '';
const model = env.get('FACIS_OPENAI_MODEL') || 'gpt-4.1-mini';

if (!apiKey) {
    msg.data = {
        topic: 'error',
        recordDetails: { message: 'OpenAI API key not configured' }
    };
    msg._socketId = msg.originalLLMRequest?.session?._socketId;
    return msg;
}

msg.url = 'https://api.openai.com/v1/chat/completions';
msg.method = 'POST';
msg.headers = {
    'Authorization': 'Bearer ' + apiKey,
    'Content-Type': 'application/json'
};
msg.payload = {
    model: model,
    messages: [
        { role: 'system', content: msg.llmSystemPrompt },
        ...msg.llmMessages
    ],
    temperature: 0.3,
    max_tokens: 2048
};
msg.selectedModel = model;

return msg;

const apiKey = env.get('FACIS_ANTHROPIC_API_KEY') || '';
const model = env.get('FACIS_ANTHROPIC_MODEL') || 'claude-sonnet-4-20250514';

if (!apiKey) {
    msg.data = {
        topic: 'error',
        recordDetails: { message: 'Anthropic API key not configured' }
    };
    msg._socketId = msg.originalLLMRequest?.session?._socketId;
    return msg;
}

msg.url = 'https://api.anthropic.com/v1/messages';
msg.method = 'POST';
msg.headers = {
    'x-api-key': apiKey,
    'anthropic-version': '2023-06-01',
    'Content-Type': 'application/json'
};
msg.payload = {
    model: model,
    max_tokens: 2048,
    system: msg.llmSystemPrompt,
    messages: msg.llmMessages
};
msg.selectedModel = model;
msg.selectedProvider = 'claude';

return msg;

const apiKey = env.get('FACIS_CUSTOM_LLM_KEY') || '';
const url = env.get('FACIS_CUSTOM_LLM_URL') || '';
const model = env.get('FACIS_CUSTOM_LLM_MODEL') || 'custom';

if (!url) {
    msg.data = {
        topic: 'error',
        recordDetails: { message: 'Custom LLM URL not configured' }
    };
    msg._socketId = msg.originalLLMRequest?.session?._socketId;
    return msg;
}

msg.url = url;
msg.method = 'POST';
msg.headers = {
    'Content-Type': 'application/json'
};
if (apiKey) {
    msg.headers['Authorization'] = 'Bearer ' + apiKey;
}

// Use OpenAI-compatible format
msg.payload = {
    model: model,
    messages: [
        { role: 'system', content: msg.llmSystemPrompt },
        ...msg.llmMessages
    ],
    temperature: 0.3,
    max_tokens: 2048
};
msg.selectedModel = model;
msg.selectedProvider = 'custom';

return msg;

const provider = msg.selectedProvider || 'openai';
const statusCode = msg.statusCode;
let text = '';

// Handle HTTP errors
if (statusCode >= 400 || !msg.payload) {
    const errMsg = msg.payload?.error?.message || msg.payload?.detail || 'LLM request failed with status ' + statusCode;
    msg.data = {
        topic: 'error',
        recordDetails: {
            message: 'LLM Error (' + provider + '): ' + errMsg
        }
    };
    msg._socketId = msg.originalLLMRequest?.session?._socketId;
    return msg;
}

// Extract text based on provider response format
try {
    if (provider === 'claude') {
        // Anthropic format: { content: [{ type: 'text', text: '...' }] }
        const content = msg.payload?.content;
        if (Array.isArray(content) && content.length > 0) {
            text = content.filter(c => c.type === 'text').map(c => c.text).join('\n');
        }
    } else {
        // OpenAI format: { choices: [{ message: { content: '...' } }] }
        text = msg.payload?.choices?.[0]?.message?.content || '';
    }
} catch(e) {
    text = 'Failed to parse LLM response: ' + e.message;
}

if (!text) {
    text = 'The AI provider returned an empty response.';
}

msg.data = {
    topic: 'llm.response',
    recordDetails: {
        response: {
            text: text,
            provider: provider,
            model: msg.selectedModel || 'unknown',
            timestamp: new Date().toISOString()
        }
    }
};
msg._socketId = msg.originalLLMRequest?.session?._socketId;

return msg;
